function curve(a: { x: number; y: number }, b: { x: number; y: number }) {
  const cx = Math.max(Math.abs(b.x - a.x) * 0.5, 80)
  return `M ${a.x} ${a.y} C ${a.x + cx} ${a.y}, ${b.x - cx} ${b.y}, ${b.x} ${b.y}`
}

