function fedRelPath(rel: FedRelation) {
  const src = nodeRight(rel.sourceTypeId)
  const tgt = nodeLeft(rel.targetTypeId)
  const sy  = rel.sourceFieldId ? src.fieldY(rel.sourceFieldId) : src.y
